#!/usr/bin/env node
/**
 * Reads design-tokens/tokens.json (W3C DTCG format, generated by @google/design.md)
 * and writes platform-specific token files to dist/.
 *
 * Outputs:
 *   dist/web/lotus-tokens.css        — CSS custom properties
 *   dist/web/_lotus-tokens.scss      — SCSS variables (replaces hand-maintained _colorPrimitives.scss)
 *   dist/ios/LotusTokens.swift       — Swift enums (UIKit / SwiftUI ready)
 *   dist/android/lotus_tokens.xml    — Android resource values XML
 */

import { readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const TOKENS_PATH = join(ROOT, 'design-tokens', 'tokens.json');

const tokens = JSON.parse(readFileSync(TOKENS_PATH, 'utf8'));

// ─── Helpers ─────────────────────────────────────────────────────────────────

function camelCase(str) {
  return str.replace(/[-_](.)/g, (_, c) => c.toUpperCase());
}

function kebabToConstant(str) {
  return str.replace(/-/g, '_').toUpperCase();
}

// Converts "grey-500" → "grey500" suitable for Swift enum member names
function swiftName(str) {
  return camelCase(str);
}

function ensure(dir) {
  mkdirSync(dir, { recursive: true });
}

// ─── Extract token groups ─────────────────────────────────────────────────────

const colors = {};
const spacing = {};
const rounded = {};
const typography = {};

for (const [groupKey, groupVal] of Object.entries(tokens)) {
  if (groupKey.startsWith('$')) continue;

  if (groupVal.$type === 'color') {
    for (const [name, token] of Object.entries(groupVal)) {
      if (name.startsWith('$')) continue;
      colors[name] = token.$value; // { colorSpace, components: [r,g,b], hex }
    }
  } else if (groupKey === 'spacing' && groupVal.$type === 'dimension') {
    for (const [name, token] of Object.entries(groupVal)) {
      if (name.startsWith('$')) continue;
      spacing[name] = token.$value; // { value, unit }
    }
  } else if (groupKey === 'rounded' && groupVal.$type === 'dimension') {
    for (const [name, token] of Object.entries(groupVal)) {
      if (name.startsWith('$')) continue;
      rounded[name] = token.$value;
    }
  } else if (groupKey === 'typography') {
    for (const [name, token] of Object.entries(groupVal)) {
      if (name.startsWith('$')) continue;
      typography[name] = token.$value; // { fontFamily, fontSize: { value, unit }, fontWeight }
    }
  }
}

// ─── SCSS ────────────────────────────────────────────────────────────────────

// Primitives: color names that follow the {word}-{number} pattern (e.g. grey-500, green-50).
// Semantics: everything else (text-primary, action-primary, surface-default, etc.).
const isPrimitive = (name) => /^[a-z]+-\d+$/.test(name);

function buildSCSS() {
  const primitiveColors = Object.entries(colors).filter(([name]) => isPrimitive(name));
  const semanticColors = Object.entries(colors).filter(([name]) => !isPrimitive(name));

  const lines = [
    '// Lotus Design Tokens — generated, do not edit',
    '// Source: design-tokens/tokens.json',
    '//',
    '// Usage (with @use namespace):',
    "//   @use '@justpark/lotus/dist/web/lotus-tokens' as lotus;",
    '//   .foo { color: lotus.$text-primary; gap: lotus.$spacing-xs; }',
    '//',
    '// Replaces: justpark-ui/src/scss/lotus/_colorPrimitives.scss',
    '// The semantic layer (_colors.scss) should @use this file instead of _colorPrimitives.',
    '',
    '// ─── Primitive colors ────────────────────────────────────────────────────────',
    '// Raw values only. Do not reference these directly in components —',
    '// use a semantic token instead.',
  ];

  for (const [name, val] of primitiveColors) {
    lines.push(`$${name}: ${val.hex};`);
  }

  lines.push('');
  lines.push('// ─── Semantic colors ────────────────────────────────────────────────────────');
  lines.push('// Purpose-named tokens. These are the values components should reference.');

  for (const [name, val] of semanticColors) {
    lines.push(`$${name}: ${val.hex};`);
  }

  lines.push('');
  lines.push('// ─── Spacing ────────────────────────────────────────────────────────────────');

  for (const [name, val] of Object.entries(spacing)) {
    lines.push(`$spacing-${name}: ${val.value}${val.unit};`);
  }

  lines.push('');
  lines.push('// ─── Border radius ──────────────────────────────────────────────────────────');

  for (const [name, val] of Object.entries(rounded)) {
    lines.push(`$rounded-${name}: ${val.value}${val.unit};`);
  }

  lines.push('');
  lines.push('// ─── Typography ─────────────────────────────────────────────────────────────');

  for (const [name, val] of Object.entries(typography)) {
    lines.push(`$typography-${name}-font-family: '${val.fontFamily}';`);
    lines.push(`$typography-${name}-font-size: ${val.fontSize.value}${val.fontSize.unit};`);
    lines.push(`$typography-${name}-font-weight: ${val.fontWeight};`);
    if (val.lineHeight !== undefined) {
      lines.push(`$typography-${name}-line-height: ${val.lineHeight};`);
    }
  }

  lines.push('');

  return lines.join('\n');
}

// ─── CSS ─────────────────────────────────────────────────────────────────────

function buildCSS() {
  const lines = [
    '/* Lotus Design Tokens — generated, do not edit */',
    '/* Source: design-tokens/tokens.json */',
    '',
    ':root {',
  ];

  lines.push('  /* Colors */');
  for (const [name, val] of Object.entries(colors)) {
    const [r, g, b] = val.components.map(c => Math.round(c * 255));
    lines.push(`  --lotus-color-${name}: ${val.hex};`);
  }

  lines.push('');
  lines.push('  /* Spacing */');
  for (const [name, val] of Object.entries(spacing)) {
    lines.push(`  --lotus-spacing-${name}: ${val.value}${val.unit};`);
  }

  lines.push('');
  lines.push('  /* Border Radius */');
  for (const [name, val] of Object.entries(rounded)) {
    lines.push(`  --lotus-rounded-${name}: ${val.value}${val.unit};`);
  }

  lines.push('');
  lines.push('  /* Typography */');
  for (const [name, val] of Object.entries(typography)) {
    lines.push(`  --lotus-typography-${name}-font-family: '${val.fontFamily}';`);
    lines.push(`  --lotus-typography-${name}-font-size: ${val.fontSize.value}${val.fontSize.unit};`);
    lines.push(`  --lotus-typography-${name}-font-weight: ${val.fontWeight};`);
    if (val.lineHeight !== undefined) {
      lines.push(`  --lotus-typography-${name}-line-height: ${val.lineHeight};`);
    }
  }

  lines.push('}');
  lines.push('');

  return lines.join('\n');
}

// ─── Swift ───────────────────────────────────────────────────────────────────

function buildSwift() {
  const lines = [
    '// Lotus Design Tokens — generated, do not edit',
    '// Source: design-tokens/tokens.json',
    '',
    'import UIKit',
    '',
    '// MARK: - Colors',
    '',
    'public enum LotusColor {',
  ];

  for (const [name, val] of Object.entries(colors)) {
    const [r, g, b] = val.components;
    const member = swiftName(name);
    lines.push(
      `    public static let ${member} = UIColor(red: ${r.toFixed(3)}, green: ${g.toFixed(3)}, blue: ${b.toFixed(3)}, alpha: 1)`
    );
  }

  lines.push('}', '');
  lines.push('// MARK: - Spacing', '');
  lines.push('public enum LotusSpacing {');

  for (const [name, val] of Object.entries(spacing)) {
    const member = swiftName(name);
    lines.push(`    public static let ${member}: CGFloat = ${val.value}`);
  }

  lines.push('}', '');
  lines.push('// MARK: - Border Radius', '');
  lines.push('public enum LotusRadius {');

  for (const [name, val] of Object.entries(rounded)) {
    const member = swiftName(name);
    lines.push(`    public static let ${member}: CGFloat = ${val.value}`);
  }

  lines.push('}', '');
  lines.push('// MARK: - Typography', '');
  lines.push('public struct LotusTypographyStyle {');
  lines.push('    public let fontFamily: String');
  lines.push('    public let fontSize: CGFloat');
  lines.push('    public let fontWeight: Int');
  lines.push('    public let lineHeight: CGFloat?');
  lines.push('}', '');
  lines.push('public enum LotusTypography {');

  for (const [name, val] of Object.entries(typography)) {
    const member = swiftName(name);
    const lh = val.lineHeight !== undefined ? `${val.lineHeight}` : 'nil';
    lines.push(
      `    public static let ${member} = LotusTypographyStyle(fontFamily: "${val.fontFamily}", fontSize: ${val.fontSize.value}, fontWeight: ${val.fontWeight}, lineHeight: ${lh})`
    );
  }

  lines.push('}', '');

  return lines.join('\n');
}

// ─── Android XML ─────────────────────────────────────────────────────────────

function buildAndroid() {
  const lines = [
    '<?xml version="1.0" encoding="utf-8"?>',
    '<!-- Lotus Design Tokens — generated, do not edit -->',
    '<!-- Source: design-tokens/tokens.json -->',
    '<resources>',
    '',
    '    <!-- Colors -->',
  ];

  for (const [name, val] of Object.entries(colors)) {
    const xmlName = `lotus_color_${name.replace(/-/g, '_')}`;
    lines.push(`    <color name="${xmlName}">${val.hex}</color>`);
  }

  lines.push('');
  lines.push('    <!-- Spacing -->');

  for (const [name, val] of Object.entries(spacing)) {
    const xmlName = `lotus_spacing_${name}`;
    lines.push(`    <dimen name="${xmlName}">${val.value}${val.unit}</dimen>`);
  }

  lines.push('');
  lines.push('    <!-- Border Radius -->');

  for (const [name, val] of Object.entries(rounded)) {
    const xmlName = `lotus_rounded_${name}`;
    lines.push(`    <dimen name="${xmlName}">${val.value}${val.unit}</dimen>`);
  }

  lines.push('');
  lines.push('    <!-- Typography: font families -->');

  for (const [name, val] of Object.entries(typography)) {
    const xmlName = `lotus_typography_${name.replace(/-/g, '_')}`;
    lines.push(`    <string name="${xmlName}_font_family">${val.fontFamily}</string>`);
    lines.push(`    <dimen name="${xmlName}_font_size">${val.fontSize.value}sp</dimen>`);
    lines.push(`    <integer name="${xmlName}_font_weight">${val.fontWeight}</integer>`);
    if (val.lineHeight !== undefined) {
      lines.push(`    <item name="${xmlName}_line_height" format="float" type="dimen">${val.lineHeight}</item>`);
    }
  }

  lines.push('', '</resources>', '');

  return lines.join('\n');
}

// ─── Write outputs ────────────────────────────────────────────────────────────

ensure(join(ROOT, 'dist', 'web'));
ensure(join(ROOT, 'dist', 'ios'));
ensure(join(ROOT, 'dist', 'android'));

writeFileSync(join(ROOT, 'dist', 'web', 'lotus-tokens.css'), buildCSS());
console.log('✓ dist/web/lotus-tokens.css');

writeFileSync(join(ROOT, 'dist', 'web', '_lotus-tokens.scss'), buildSCSS());
console.log('✓ dist/web/_lotus-tokens.scss');

writeFileSync(join(ROOT, 'dist', 'ios', 'LotusTokens.swift'), buildSwift());
console.log('✓ dist/ios/LotusTokens.swift');

writeFileSync(join(ROOT, 'dist', 'android', 'lotus_tokens.xml'), buildAndroid());
console.log('✓ dist/android/lotus_tokens.xml');
